[
  {
    "file": "src/Components/Web/src/Forms/ExpressionMemberAccessor.cs",
    "line": 88,
    "severity": "critical",
    "description": "The ClearCache() method only clears _memberInfoCache but not _displayNameCache. During hot reload, when metadata is updated, the display name cache becomes stale because it is never cleared. This causes GetDisplayName() to return outdated cached values even after attributes have been modified.",
    "fix_patch": "--- a/src/Components/Web/src/Forms/ExpressionMemberAccessor.cs
+++ b/src/Components/Web/src/Forms/ExpressionMemberAccessor.cs
@@ -86,5 +86,6 @@ namespace Microsoft.AspNetCore.Components.Forms;
     private static void ClearCache()
     {
         _memberInfoCache.Clear();
+        _displayNameCache.Clear();
     }
"
  },
  {
    "file": "src/Components/Web/src/Forms/ExpressionMemberAccessor.cs",
    "line": 59,
    "severity": "high",
    "description": "The code checks [DisplayName] attribute before [Display] attribute, but ASP.NET Core conventions dictate that [Display] (the modern DataAnnotations attribute) should take precedence over [DisplayName] (the legacy ComponentModel attribute). The documentation comment lists 'DisplayAttribute' first, implying it should be checked first. When both attributes are present, the wrong one takes precedence.",
    "fix_patch": "--- a/src/Components/Web/src/Forms/ExpressionMemberAccessor.cs
+++ b/src/Components/Web/src/Forms/ExpressionMemberAccessor.cs
@@ -56,17 +56,17 @@ namespace Microsoft.AspNetCore.Components.Forms;
     {
         ArgumentNullException.ThrowIfNull(member);

         return _displayNameCache.GetOrAdd(member, static m =>
         {
+            var displayAttribute = m.GetCustomAttribute<DisplayAttribute>();
+            if (displayAttribute is not null)
+            {
+                var name = displayAttribute.GetName();
+                if (name is not null)
+                {
+                    return name;
+                }
+            }
+
             var displayNameAttribute = m.GetCustomAttribute<DisplayNameAttribute>();
             if (displayNameAttribute?.DisplayName is not null)
             {
                 return displayNameAttribute.DisplayName;
             }

-            var displayAttribute = m.GetCustomAttribute<DisplayAttribute>();
-            if (displayAttribute is not null)
-            {
-                var name = displayAttribute.GetName();
-                if (name is not null)
-                {
-                    return name;
-                }
-            }

             return m.Name;
         });
"
  },
  {
    "file": "src/Components/Web/src/Forms/DisplayName.cs",
    "line": 35,
    "severity": "high",
    "description": "The SetParametersAsync method always renders the component without checking if the For parameter has actually changed. The unused _previousFieldAccessor field (line 20) indicates an incomplete optimization. The component should track whether the For expression changed by reference and only update/render when it does, following standard Blazor component optimization practices. Currently, the component re-renders unnecessarily on every parameter update.",
    "fix_patch": "--- a/src/Components/Web/src/Forms/DisplayName.cs
+++ b/src/Components/Web/src/Forms/DisplayName.cs
@@ -35,10 +35,14 @@ namespace Microsoft.AspNetCore.Components.Forms;
     /// <inheritdoc />
     Task IComponent.SetParametersAsync(ParameterView parameters)
     {
         parameters.SetParameterProperties(this);

-        var newDisplayName = ExpressionMemberAccessor.GetDisplayName(For);
-        _displayName = newDisplayName;
-        _renderHandle.Render(BuildRenderTree);
+        if (!ReferenceEquals(_previousFieldAccessor, For))
+        {
+            _previousFieldAccessor = For;
+            var newDisplayName = ExpressionMemberAccessor.GetDisplayName(For);
+            _displayName = newDisplayName;
+            _renderHandle.Render(BuildRenderTree);
+        }

         return Task.CompletedTask;
     }
"
  }
]

